**Configuration iOS** : ajouter dans `app.json` la clé `NSFaceIDUsageDescription` :
```json
{
  "expo": {
    "ios": {
      "infoPlist": {
        "NSFaceIDUsageDescription": "Cette application utilise Face ID pour vous connecter rapidement et en toute sécurité."
      }
    }
  }
}
```

**Configuration Android** : aucune configuration supplémentaire requise. L'API utilise le capteur d'empreintes du système.

```typescript
import * as LocalAuthentication from 'expo-local-authentication';

async function checkBiometricSupport() {
  try {
    // Vérifier si l'appareil a un capteur biométrique
    const hasHardware = await LocalAuthentication.hasHardwareAsync();
    if (!hasHardware) {
      return { isAvailable: false, reason: 'Aucun capteur biométrique détecté' };
    }

    // Vérifier si des données biométriques sont enregistrées
    const isEnrolled = await LocalAuthentication.isEnrolledAsync();
    if (!isEnrolled) {
      return { isAvailable: false, reason: 'Aucune empreinte / Face ID configuré' };
    }

    // Récupérer les types supportés
    const supportedTypes = await LocalAuthentication.supportedAuthenticationTypesAsync();

    const typesMap = {
      [LocalAuthentication.AuthenticationType.FINGERPRINT]: 'empreinte digitale',
      [LocalAuthentication.AuthenticationType.FACIAL_RECOGNITION]: 'reconnaissance faciale',
      [LocalAuthentication.AuthenticationType.IRIS]: 'reconnaissance irienne',
    };

    const availableMethods = supportedTypes.map(type => typesMap[type]).filter(Boolean);

    return { 
      isAvailable: true, 
      availableMethods,
      reason: `Biométrie disponible : ${availableMethods.join(', ')}`
    };
  } catch (error) {
    return { isAvailable: false, reason: error.message };
  }
}
```

```typescript
import * as LocalAuthentication from 'expo-local-authentication';
import * as SecureStore from 'expo-secure-store';
import { loginUser } from '../services/authService';

async function authenticateWithBiometrics() {
  // 1. Vérifier la disponibilité
  const hasHardware = await LocalAuthentication.hasHardwareAsync();
  const isEnrolled = await LocalAuthentication.isEnrolledAsync();

  if (!hasHardware || !isEnrolled) {
    throw new Error('Biométrie non disponible ou non configurée');
  }

  // 2. Lancer l'authentification
  const result = await LocalAuthentication.authenticateAsync({
    promptMessage: 'Connectez-vous avec votre empreinte ou Face ID',
    fallbackLabel: 'Utiliser le mot de passe',
    cancelLabel: 'Annuler',
    disableDeviceFallback: false,
  });

  if (!result.success) {
    throw new Error('Authentification biométrique échouée');
  }

  // 3. Récupérer les identifiants stockés de manière sécurisée
  const storedEmail = await SecureStore.getItemAsync('user_email');
  const storedPassword = await SecureStore.getItemAsync('user_password_hash');

  if (!storedEmail || !storedPassword) {
    throw new Error('Aucun identifiant stocké. Veuillez vous connecter manuellement d\'abord.');
  }

  // 4. Appeler l'API de connexion
  const response = await loginUser(storedEmail, storedPassword);
  return response;
}

// Utilisation dans un composant
function LoginScreen() {
  const handleBiometricLogin = async () => {
    try {
      const user = await authenticateWithBiometrics();
      navigation.replace('Home');
      Toast.show('Connexion réussie');
    } catch (error) {
      Toast.show(error.message);
    }
  };

  return (
    <TouchableOpacity onPress={handleBiometricLogin}>
      <Text>🔐 Connexion biométrique</Text>
    </TouchableOpacity>
  );
}
```

```typescript
async function handleBiometricLoginWithFallback() {
  try {
    // 1. Vérification matérielle
    const hasHardware = await LocalAuthentication.hasHardwareAsync();
    if (!hasHardware) {
      return { success: false, error: 'NO_HARDWARE', message: 'Votre appareil ne dispose pas de capteur biométrique.' };
    }

    // 2. Vérification des données enrôlées
    const isEnrolled = await LocalAuthentication.isEnrolledAsync();
    if (!isEnrolled) {
      return { 
        success: false, 
        error: 'NOT_ENROLLED', 
        message: 'Aucune empreinte ou Face ID configuré sur cet appareil. Veuillez en ajouter un dans les paramètres.',
        action: 'OPEN_SETTINGS'
      };
    }

    // 3. Tentative d'authentification
    const result = await LocalAuthentication.authenticateAsync({
      promptMessage: 'Vérification d\'identité',
      cancelLabel: 'Annuler',
      fallbackLabel: 'Mot de passe',
      disableDeviceFallback: false,
    });

    if (!result.success) {
      // Analyser le type d'erreur
      if (result.error === 'user_cancel') {
        return { success: false, error: 'USER_CANCEL', message: 'Authentification annulée par l\'utilisateur' };
      }
      if (result.error === 'system_cancel') {
        return { success: false, error: 'SYSTEM_CANCEL', message: 'Authentification annulée par le système (popup fermée)' };
      }
      if (result.error === 'not_available') {
        return { success: false, error: 'NOT_AVAILABLE', message: 'Service biométrique temporairement indisponible' };
      }
      if (result.error === 'lockout') {
        return { 
          success: false, 
          error: 'LOCKOUT', 
          message: 'Trop de tentatives échouées. Veuillez vous connecter avec votre mot de passe.',
          action: 'FORCE_PASSWORD'
        };
      }
      return { success: false, error: 'UNKNOWN', message: 'Échec de l\'authentification' };
    }

    // 4. Succès : récupérer et utiliser les identifiants
    const credentials = await getStoredCredentials();
    return { success: true, credentials };

  } catch (error) {
    return { success: false, error: 'EXCEPTION', message: error.message };
  }
}

// Utilisation dans l'UI
const result = await handleBiometricLoginWithFallback();
if (!result.success) {
  if (result.action === 'OPEN_SETTINGS') {
    // Rediriger vers les paramètres système (nécessite Linking)
    Linking.openSettings();
  } else if (result.action === 'FORCE_PASSWORD') {
    // Afficher formulaire de connexion classique
    showPasswordLogin();
  } else {
    Alert.alert('Erreur', result.message);
  }
}
