```typescript
import * as LocalAuthentication from 'expo-local-authentication';
import * as SecureStore from 'expo-secure-store';
import CryptoJS from 'crypto-js'; // ou expo-crypto

async function enableBiometricLogin(email: string, password: string) {
  // 1. Vérifier que la biométrie est disponible
  const hasHardware = await LocalAuthentication.hasHardwareAsync();
  const isEnrolled = await LocalAuthentication.isEnrolledAsync();

  if (!hasHardware || !isEnrolled) {
    throw new Error('Biométrie non disponible');
  }

  // 2. Demander confirmation biométrique avant d'activer
  const auth = await LocalAuthentication.authenticateAsync({
    promptMessage: 'Activez la connexion rapide',
  });

  if (!auth.success) {
    throw new Error('Authentification requise pour activer la biométrie');
  }

  // 3. Hacher le mot de passe (ne jamais stocker en clair)
  const passwordHash = CryptoJS.SHA256(password).toString();

  // 4. Stocker les identifiants dans SecureStore
  await SecureStore.setItemAsync('user_email', email);
  await SecureStore.setItemAsync('user_password_hash', passwordHash);
  await SecureStore.setItemAsync('biometric_enabled', 'true');
  await SecureStore.setItemAsync('biometric_enrolled_at', Date.now().toString());
}

async function disableBiometricLogin() {
  // Demander confirmation biométrique avant de désactiver
  const auth = await LocalAuthentication.authenticateAsync({
    promptMessage: 'Désactiver la connexion rapide ?',
  });

  if (!auth.success) {
    throw new Error('Authentification requise pour désactiver');
  }

  await SecureStore.deleteItemAsync('user_email');
  await SecureStore.deleteItemAsync('user_password_hash');
  await SecureStore.setItemAsync('biometric_enabled', 'false');
  await SecureStore.deleteItemAsync('biometric_enrolled_at');
}

async function isBiometricLoginAvailable(): Promise<boolean> {
  const enabled = await SecureStore.getItemAsync('biometric_enabled');
  if (enabled !== 'true') return false;

  const hasHardware = await LocalAuthentication.hasHardwareAsync();
  const isEnrolled = await LocalAuthentication.isEnrolledAsync();

  return hasHardware && isEnrolled;
}
